function [p,minX,maxX] = fPolyfitV01(x,y,ord)%% Perform polyfit to particular case for focus%% [p,maxX,minX] = fPolyfitV01(x,y,ord)%% x,y: x an y% ord: order for polyfit%% p: polynomial coeff.% minX, maxX: x gives min/max y% %%  %%%%%%%%%%%%%%%%%%%%%%%%%%%%% polyfit for min and max, ver.1%% Kei Nakamura% Created on Friday, October 28th 2011.% Modified on %% ver.1: created%%%%%%%%%%%%%%%%%%%%%%%%%%%%% main bodyp = polyfit(x,y,ord);%step = (max(x)-min(x))/99;%polXi = min(x):step:max(x);polXi = linspace(min(x), max(x), 200);% get max[~,maxI] = max(polyval(p,polXi));maxX = polXi(maxI);% get min[~,minI] = min(polyval(p,polXi));minX = polXi(minI);
